package pe.org.camaracomercioica.protestos.model;
import jakarta.persistence.*; import lombok.*; import java.time.Instant;
@Entity @Table(name="solicitudes") @Getter @Setter @NoArgsConstructor
public class Solicitud { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,unique=true,length=30) private String codigo; @ManyToOne(optional=false) @JoinColumn(name="solicitante_id") private Usuario solicitante; @ManyToOne(optional=false) @JoinColumn(name="entidad_id") private EntidadFinanciera entidad; @ManyToOne @JoinColumn(name="analista_id") private Analista analista; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) private EstadoSolicitud estado=EstadoSolicitud.REGISTRADA; @Column(nullable=false,length=1000) private String motivo; @Column(length=1000) private String observacion; @Column(nullable=false,updatable=false) private Instant creadoEn=Instant.now(); @Column(nullable=false) private Instant actualizadoEn=Instant.now(); }
